const input = $input.first().json;
const required = ['client_id','client_slug','client_name','owner_email','field_map','google_review_link'];
const missing = required.filter(k => !input[k]);
if (missing.length > 0) throw new Error('Missing required fields: ' + missing.join(', '));

let fieldMap;
try { fieldMap = JSON.parse(input.field_map); } catch(e) { throw new Error('field_map must be valid JSON'); }
if (Object.keys(fieldMap).length === 0) throw new Error('field_map must have at least one entry');

const leadHeaders = [...Object.keys(fieldMap), 'Source', 'Status', 'Notes', 'Score', 'Score Reason', 'Contacted At', 'Booked At', 'Lead ID', 'Submitted At'];
const reviewHeaders = ['Lead Name', 'Phone', 'Review Sent', 'Rating'];

return [{ json: {
  client_id: input.client_id,
  client_slug: input.client_slug,
  client_name: input.client_name,
  owner_email: input.owner_email,
  field_map: input.field_map,
  google_review_link: input.google_review_link,
  lead_headers: leadHeaders,
  review_headers: reviewHeaders,
  spreadsheet_title: input.client_name + ' - Leads',
} }];

const sheet = $input.first().json;
const v = $('Validate Input').first().json;
const leadSheetId = (sheet.sheets && sheet.sheets[0]) ? sheet.sheets[0].properties.sheetId : 0;
return [{ json: {
  spreadsheet_id: sheet.spreadsheetId,
  sheet_url: 'https://docs.google.com/spreadsheets/d/' + sheet.spreadsheetId,
  lead_sheet_id: leadSheetId,
  client_id: v.client_id,
  client_slug: v.client_slug,
  client_name: v.client_name,
  owner_email: v.owner_email,
  field_map: v.field_map,
  google_review_link: v.google_review_link,
  lead_headers: v.lead_headers,
  review_headers: v.review_headers,
} }];

const data = $input.first().json;
const fieldMapObj = JSON.parse(data.field_map);
const statusColIndex = Object.keys(fieldMapObj).length + 1;
const statusValues = ['New','Contacted','Booked','Completed','Not Interested','No Show'];
const endCol = String.fromCharCode(64 + data.lead_headers.length);
return [{ json: {
  spreadsheet_id: data.spreadsheet_id,
  sheet_url: data.sheet_url,
  client_id: data.client_id,
  client_slug: data.client_slug,
  client_name: data.client_name,
  owner_email: data.owner_email,
  field_map: data.field_map,
  google_review_link: data.google_review_link,
  lead_sheet_id: data.lead_sheet_id,
  status_col_index: statusColIndex,
  lead_range: 'Leads!A1:' + endCol + '1',
  lead_values: JSON.stringify({ values: [data.lead_headers] }),
  review_range: 'Review Status!A1:D1',
  review_values: JSON.stringify({ values: [data.review_headers] }),
  batch_update_body: JSON.stringify({
    requests: [{
      setDataValidation: {
        range: { sheetId: data.lead_sheet_id, startRowIndex: 1, endRowIndex: 10000, startColumnIndex: statusColIndex, endColumnIndex: statusColIndex + 1 },
        rule: { condition: { type: 'ONE_OF_LIST', values: statusValues.map(v => ({ userEnteredValue: v })) }, showCustomUi: true, strict: true }
      }
    }]
  })
} }];

const data = $('Build Payloads').first().json;
let secret = '';
while (secret.length < 64) { secret += Math.floor(Math.random() * 16).toString(16); }
secret = secret.slice(0, 64);
return [{ json: {
  spreadsheet_id: data.spreadsheet_id,
  sheet_url: data.sheet_url,
  client_id: data.client_id,
  client_slug: data.client_slug,
  client_name: data.client_name,
  owner_email: data.owner_email,
  field_map: data.field_map,
  google_review_link: data.google_review_link,
  link_signing_secret: secret,
} }];
